import React from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import { AuthProvider, useAuth } from './context/AuthContext';
import { NavigationProvider } from './context/NavigationContext';
import Navbar from './components/Navbar';
import Notifications from './components/Notifications';
import Loading from './components/Loading';
import Home from './pages/Home';
import Login from './pages/Login';
import Register from './pages/Register';
import GameDetail from './pages/GameDetail';
import Cart from './pages/Cart';
import Profile from './pages/Profile';
import Favorites from './pages/Favorites';
import GoogleCallback from './pages/GoogleCallback';
import TestBackend from './pages/TestBackend';

const AdminDashboard = () => {
  const { state } = useAuth();

  if (!state.isAuthenticated || state.user?.role !== 'admin') {
    return (
      <div className="min-h-screen bg-gray-900 text-white flex items-center justify-center">
        <div className="text-center">
          <h1 className="text-4xl font-bold mb-4">غير مصرح بالوصول</h1>
          <p className="text-xl mb-8">يجب تسجيل الدخول كمدير للوصول إلى هذه الصفحة</p>
          <Navigate to="/login" replace />
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-900 text-white p-6">
      <div className="max-w-7xl mx-auto">
        <div className="mb-8">
          <h1 className="text-4xl font-bold mb-2">لوحة تحكم الإدمن</h1>
          <p className="text-gray-400">مرحباً Admin</p>
        </div>

        <div className="bg-gray-800 rounded-lg p-6">
          <h2 className="text-2xl font-bold mb-4">مرحباً في لوحة التحكم</h2>
          <p className="text-gray-400 mb-6">هذه لوحة تحكم الإدمن البسيطة</p>

          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
            <div className="bg-gray-700 rounded-lg p-4 text-center">
              <h3 className="text-lg font-bold mb-2">إدارة الألعاب</h3>
              <p className="text-gray-400 text-sm">إدارة وتعديل الألعاب المتوفرة</p>
            </div>

            <div className="bg-gray-700 rounded-lg p-4 text-center">
              <h3 className="text-lg font-bold mb-2">إدارة المستخدمين</h3>
              <p className="text-gray-400 text-sm">عرض وإدارة حسابات المستخدمين</p>
            </div>

            <div className="bg-gray-700 rounded-lg p-4 text-center">
              <h3 className="text-lg font-bold mb-2">إدارة الطلبات</h3>
              <p className="text-gray-400 text-sm">متابعة وتجهيز الطلبات</p>
            </div>

            <div className="bg-gray-700 rounded-lg p-4 text-center">
              <h3 className="text-lg font-bold mb-2">الإحصائيات</h3>
              <p className="text-gray-400 text-sm">عرض إحصائيات وتقارير الموقع</p>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

const App = () => {
  return (
    <Router>
      <AuthProvider>
        <NavigationProvider>
          <div className="min-h-screen bg-gray-900 text-white">
            <Navbar />
            <main className="max-w-7xl mx-auto px-4 py-8">
              <Routes>
                <Route path="/" element={<Home />} />
                <Route path="/login" element={<Login />} />
                <Route path="/register" element={<Register />} />
                <Route path="/game/:id" element={<GameDetail />} />
                <Route path="/cart" element={<Cart />} />
                <Route path="/profile" element={<Profile />} />
                <Route path="/favorites" element={<Favorites />} />
                <Route path="/google/callback" element={<GoogleCallback />} />
                <Route path="/test-backend" element={<TestBackend />} />
                <Route path="/admin" element={<AdminDashboard />} />
                <Route path="*" element={<Navigate to="/" replace />} />
              </Routes>
            </main>
            <Notifications />
          </div>
        </NavigationProvider>
      </AuthProvider>
    </Router>
  );
};

export default App;
